import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is ROI?", a: "ROI, or return on investment, measures profit or gain compared with the original investment cost." },
  { q: "How do you calculate ROI?", a: "ROI equals net profit divided by initial investment cost, multiplied by 100." },
  { q: "What is a good ROI?", a: "A good ROI depends on the investment type, risk, liquidity, time horizon, and available alternatives." },
  { q: "What is the difference between ROI and IRR?", a: "ROI is a simple return percentage, while IRR accounts for the timing of multiple cash flows over time." },
  { q: "How do you calculate annualized ROI?", a: "Annualized ROI converts total ROI into an equivalent yearly compounded return over the holding period." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function ROICalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState("final");
  const [cost, setCost] = useState(10000);
  const [finalValue, setFinalValue] = useState(15000);
  const [profitInput, setProfitInput] = useState(5000);
  const [years, setYears] = useState(5);
  const result = useMemo(() => {
    const profit = mode === "profit" ? profitInput : finalValue - cost;
    const roi = cost ? profit / cost * 100 : 0;
    const annualized = cost > 0 && years > 0 ? (Math.pow((cost + profit) / cost, 1 / years) - 1) * 100 : 0;
    return { profit, roi, annualized, final: cost + profit };
  }, [mode, cost, finalValue, profitInput, years]);
  const investments = [
    ["Savings Account", 4, "Low", "High"],
    ["Bonds", 5, "Low-Medium", "Medium"],
    ["Index Funds", 8, "Medium", "High"],
    ["Real Estate", 7, "Medium", "Low"],
    ["Business", 15, "High", "Low"],
    ["Crypto", 20, "Very High", "High"],
  ];
  return (
    <>
      <SEOHead title="Free ROI Calculator Online - Calculate Return on Investment Instantly | CalcHive" description="Free online ROI calculator. Calculate return on investment percentage, annualized ROI and total profit for any investment instantly. 100% free, no signup required." canonical="/roi-calculator" keywords="free ROI calculator, return on investment calculator free online, calculate ROI free, investment return calculator free, annualized ROI calculator free online" category="Financial Calculators" breadcrumbName="Free ROI Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free ROI Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate return on investment, annualized ROI, total profit, and final value.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value)} className={inputClass}><option value="final">Use final value</option><option value="profit">Use net profit</option></select></div><div><label className="text-sm font-semibold text-foreground block mb-2">Initial investment cost</label><input type="number" value={cost} onChange={(e) => setCost(Number(e.target.value))} className={inputClass} /></div>{mode === "final" ? <div><label className="text-sm font-semibold text-foreground block mb-2">Final value</label><input type="number" value={finalValue} onChange={(e) => setFinalValue(Number(e.target.value))} className={inputClass} /></div> : <div><label className="text-sm font-semibold text-foreground block mb-2">Net profit</label><input type="number" value={profitInput} onChange={(e) => setProfitInput(Number(e.target.value))} className={inputClass} /></div>}<div><label className="text-sm font-semibold text-foreground block mb-2">Holding period years</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Return on Investment</p><p className="text-5xl sm:text-6xl font-black text-white">{pct(result.roi)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Annualized ROI</p><p className="text-lg font-extrabold text-foreground">{pct(result.annualized)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total profit</p><p className="text-lg font-extrabold text-foreground">{money(result.profit)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Final value</p><p className="text-lg font-extrabold text-foreground">{money(result.final)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Return on Investment for Free</h2><p className="text-muted-foreground leading-relaxed">Divide net gain by initial cost and multiply by 100 to calculate ROI.</p><h2 className="text-2xl font-bold text-foreground">How to Calculate Annualized ROI for Any Time Period</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">ROI Comparison by Investment Type</caption><thead className="bg-muted/60"><tr>{["Investment Type", "Typical Annual ROI", "10 Year $10K Growth", "Risk Level", "Liquidity"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{investments.map(([type, roi, risk, liquidity]) => <tr key={String(type)}><td className="py-2.5 px-3 font-semibold">{String(type)}</td><td className="py-2.5 px-3">{roi}%</td><td className="py-2.5 px-3">{money(10000 * Math.pow(1 + Number(roi) / 100, 10))}</td><td className="py-2.5 px-3">{String(risk)}</td><td className="py-2.5 px-3">{String(liquidity)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Investment ROI Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use ROI for simple investment comparisons and annualized ROI when time period matters.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/roi-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


